buttons:
setRole(r)}
                  className={`p-4 rounded-2xl text-sm font-bold text-left border transition-all ${
                    role === r 
                      ? 'bg-deep-black text-warm-cream border-deep-black shadow-soft' 
                      : 'bg-warm-cream text-text-secondary border-border-subtle hover:border-deep-black'
                  }`}
                >

                    {r === 'Data Scientist' ?  : 
                     r === 'Approver' ?  : 
                     }

                  {r}

setFilter(f)}
                className={`px-5 py-2 rounded-full text-sm font-bold transition-all duration-300 border ${
                  filter === f 
                    ? 'bg-deep-black text-warm-cream border-deep-black' 
                    : 'bg-white text-text-secondary border-border-subtle hover:border-deep-black hover:text-text-primary shadow-soft'
                }`}
              >
                {f}

setShowCreate(!showCreate)}
          className="px-6 py-3 bg-electric-mint text-deep-black rounded-full font-bold shadow-glow-mint hover:scale-105 transition-transform flex items-center gap-2"
        >
          {showCreate ? 'Close Builder' : <> New Campaign}

setChannel(ch)}
                    className={`py-3 px-2 rounded-xl text-xs font-bold border transition-colors ${channel === ch ? 'bg-butter-yellow text-deep-black border-butter-yellow' : 'bg-white/5 text-white/70 border-white/10 hover:border-white/30'}`}
                  >
                    {ch}

setShowInvite(!showInvite)}
          className="px-6 py-3 bg-electric-mint text-deep-black rounded-full font-bold shadow-glow-mint hover:scale-105 transition-transform flex items-center gap-2"
        >
          {showInvite ? 'Close Form' : <> Invite Member}

setActiveTab(tab)}
              className={`text-left px-5 py-4 rounded-2xl text-sm font-bold transition-all ${
                activeTab === tab 
                  ? 'bg-deep-black text-warm-cream shadow-soft' 
                  : 'text-text-secondary hover:bg-warm-cream hover:text-deep-black'
              }`}
            >
              {tab}
